UPDATE pool_models SET descricao = 'O modelo mais vendido no Brasil da linha Splash. Design elegante com formas arredondadas, seguindo tendência de produtos com apelo criativo. Disponível na maior variedade de tamanhos.' WHERE nome_modelo = 'Italiana';
UPDATE pool_models SET descricao = 'Piscina de poliéster com borda infinita, Prainha e pastilhas nas bordas. A borda infinita espelha a paisagem na água, garantindo leveza e requinte. O modelo mais glamouroso e sofisticado da linha. Tamanho único.' WHERE nome_modelo = 'Nassau';
UPDATE pool_models SET descricao = 'A linha mais completa da Splash. Possui SPA integrado e deck molhado (Prainha), projetada para áreas de lazer amplas. Permite uso simultâneo da piscina, prainha e SPA.' WHERE nome_modelo = 'Atalaia';
UPDATE pool_models SET descricao = 'Piscina de poliéster com design clássico retangular. Bordas das paredes internas pastilhadas de fábrica. Possui banco com hidromassagem e escada em lados opostos. Um dos modelos mais valorizados da linha Splash.' WHERE nome_modelo = 'Bonaire';
UPDATE pool_models SET descricao = 'Piscina de poliéster com design tradicional retangular e grande aproveitamento de área útil. Diferencial: banco com hidro, escadas e hidroterapia do mesmo lado. Ideal para áreas amplas de lazer.' WHERE nome_modelo = 'Cancún';
UPDATE pool_models SET descricao = 'Piscina de fibra clássica e versátil, com bordas arredondadas. Ideal para espaço exclusivo e seguro para família e amigos. Ampla variedade de tamanhos.' WHERE nome_modelo = 'Farol da Barra';
UPDATE pool_models SET descricao = 'O modelo mais moderno e exclusivo da linha Splash. Design com linhas retas e formato retangular sofisticado. Diferencial exclusivo: painéis de acrílico personalizáveis. Todas as versões com Pastilhas de Porcelana Atlas incluídas.' WHERE nome_modelo = 'Navagio';
UPDATE pool_models SET descricao = 'Piscina de poliéster com forma retangular e Prainha integrada, ideal para áreas maiores. Disponível nas versões sem banco e com banco. Pode ser personalizada com pastilhas coloridas.' WHERE nome_modelo = 'Tortuga';
UPDATE pool_models SET descricao = 'Piscina de poliéster com formas retangulares e cantos arredondados, elaborada para maior aproveitamento de espaço. Design elegante e sofisticado. Disponível nas versões padrão, com Prainha, com SPA e com Pastilhas de Porcelana Atlas.' WHERE nome_modelo = 'Tradicional';
UPDATE pool_models SET descricao = 'Piscina de poliéster com conceito de produto completo para relaxar em família. Formato elegante com ampla variedade de tamanhos. Alta qualidade e durabilidade.' WHERE nome_modelo = 'Tropical';